    /**
     * Check health status of a specific model
     */
    async checkModelHealth(modelName: string): Promise<ModelHealthStatus> {
        const startTime = Date.now();
        try {
            // Try to get model info and run a minimal inference
            const response = await this.httpRequest({
                method: 'POST',
                path: '/api/generate',
                body: JSON.stringify({
                    model: modelName,
                    prompt: 'test',
                    stream: false,
                    options: { num_predict: 1 }
                }),
                timeout: 30000
            });

            const responseTimeMs = Date.now() - startTime;

            if (response.ok) {
                const models = await this.getModels();
                const modelInfo = models.find(m => m.name === modelName);

                return {
                    name: modelName,
                    isHealthy: true,
                    lastChecked: new Date(),
                    responseTimeMs,
                    size: modelInfo?.size ?? 0,
                    digest: modelInfo?.digest ?? '',
                    details: modelInfo?.details
                };
            } else {
                return {
                    name: modelName,
                    isHealthy: false,
                    lastChecked: new Date(),
                    responseTimeMs,
                    error: `HTTP ${response.status}: ${response.data}`,
                    size: 0,
                    digest: ''
                };
            }
        } catch (error) {
            return {
                name: modelName,
                isHealthy: false,
                lastChecked: new Date(),
                responseTimeMs: Date.now() - startTime,
                error: getErrorMessage(error as Error),
                size: 0,
                digest: ''
            };
        }
    }

