}

interface MessageActionsContextProps {
    displayContent: string;
    message: Message;
    isSpeaking?: boolean;
    onStop?: () => void;
    onSpeak?: (text: string) => void;
    onBookmark?: (isBookmarked: boolean) => void;
    onReact?: (emoji: string) => void;
    onRate?: (rating: 1 | -1 | 0) => void;
    onRegenerate?: () => void;
    onSourceClick?: (path: string) => void;
