        isStreaming,
        displayContent,
        quotaDetails,
        message,
        contentProps,
        actionsContextProps,
    }: MessageBubbleInnerProps) => {
        const { showToggle, showActions } = createToggleVisibilityFlags(
            displayContent,
            isUser,
            quotaDetails
        );
        const bubbleClass = isUser
            ? 'bg-muted/10 px-4 py-3 rounded-tr-sm border border-border/50 text-foreground/90'
