const useMessageContent = (
    raw: Message['content'],
    reasoning: string | undefined,
    streaming: string | undefined
) =>
    useMemo(() => {
        let content =
            typeof raw === 'string'
                ? raw
                : Array.isArray(raw)
                  ? raw
                        .map(c => {
                            if (typeof c === 'string') {
                                return c;
                            }
                            if (c.type === 'text') {
                                return c.text;
                            }
                            return '';
                        })
                        .join('')
                  : '';
        let r = reasoning ?? null;
        if (!r) {
            const m = /<think>([\s\S]*?)(?:<\/think>|$)/.exec(content);
            if (m) {
                r = m[1];
                content = content.replace(/<think>[\s\S]*?(?:<\/think>|$)/, '');
            }
        }
        const pm = /<plan>([\s\S]*?)(?:<\/plan>|$)/.exec(content);
        let p = null;
        if (pm) {
            p = pm[1];
            content = content.replace(/<plan>[\s\S]*?(?:<\/plan>|$)/, '');
        }
        return { thought: streaming ?? r, plan: p, displayContent: content.trim() };
    }, [raw, reasoning, streaming]);

interface QuotaErrorResponse {
    message?: string;
    resets_at?: number;
    model?: string;
    error?: {
        message?: string;
        resets_at?: number;
        model?: string;
    };
}

const useQuotaDetails = (is429: boolean, content: string, t: TranslationFn) =>
    useMemo(() => {
        if (!is429) {
            return null;
        }
        try {
            const m = content.match(/\{[\s\S]*\}/);
            if (m) {
                const d = safeJsonParse<QuotaErrorResponse>(m[0], {});
                const o = d.error ?? d;
                return {
                    message: o.message ?? t('messageBubble.quotaExceeded'),
                    resets_at: o.resets_at ?? null,
                    model: o.model ?? null,
                };
            }
        } catch {
            /* skip */
        }
        return { message: t('messageBubble.quotaMessage'), resets_at: null, model: null };
    }, [is429, content, t]);

