    const startRecording = useCallback(() => {
        const tabId = activeTabIdRef.current;
        if (!tabId) {
            return;
        }
        const tab = tabsRef.current.find(item => item.id === tabId);
        if (!tab) {
            return;
        }

        if (recordingCaptureRef.current) {
            completeRecording();
