import { useTranslation } from '@renderer/i18n';
import { memo, useCallback, useEffect, useRef, useState } from 'react';
import { ITheme, Terminal as XTerm } from 'xterm';
import { FitAddon } from 'xterm-addon-fit';

import { useTerminalSmartSuggestions } from '@/features/terminal/hooks/useTerminalSmartSuggestions';
import { cn } from '@/lib/utils';
import type { TerminalTab } from '@/types';
import { appLogger } from '@/utils/renderer-logger';

import type {
    ResolvedTerminalAppearance,
    TerminalAppearancePreferences,
} from '../types/terminal-appearance';
import {
    clearTerminalSessionFlags,
    isTerminalSessionInitialized,
    isTerminalSessionInitializing,
    markTerminalSessionInitialized,
    markTerminalSessionInitializing,
} from '../utils/session-registry';

type DetectedTerminalLink = {
    text: string;
    target: string;
    start: number;
    end: number;
    type: 'url' | 'path';
};

const URL_LINK_REGEX = /\bhttps?:\/\/[^\s<>"'`]+/gi;
const WINDOWS_PATH_LINK_REGEX = /\b[A-Za-z]:[\\/][^\s"'`<>|]+/g;
const UNIX_PATH_LINK_REGEX = /(?:^|[\s([{'"`])(\/[^\s"'`<>()`]+)/g;
const TRAILING_LINK_CHARACTERS_REGEX = /[.,;:!?)}\]'"]+$/;

function trimTrailingLinkCharacters(value: string): string {
    let normalized = value;
    while (TRAILING_LINK_CHARACTERS_REGEX.test(normalized)) {
        normalized = normalized.replace(TRAILING_LINK_CHARACTERS_REGEX, '');
    }
    return normalized;
}

function normalizePathLinkTarget(path: string): string {
    const withoutLineColumn = path.replace(/(?::\d+){1,2}$/, '');
    return trimTrailingLinkCharacters(withoutLineColumn);
}

function resolveTerminalLineLinks(lineText: string): DetectedTerminalLink[] {
    if (!lineText) {
        return [];
    }

    const matches: DetectedTerminalLink[] = [];

    URL_LINK_REGEX.lastIndex = 0;
    for (let match = URL_LINK_REGEX.exec(lineText); match; match = URL_LINK_REGEX.exec(lineText)) {
        const rawText = match[0] ?? '';
        const text = trimTrailingLinkCharacters(rawText);
        if (!text) {
            continue;
        }
        const start = match.index;
        const end = start + text.length;
        matches.push({ text, target: text, start, end, type: 'url' });
    }

    WINDOWS_PATH_LINK_REGEX.lastIndex = 0;
    for (
        let match = WINDOWS_PATH_LINK_REGEX.exec(lineText);
        match;
        match = WINDOWS_PATH_LINK_REGEX.exec(lineText)
    ) {
        const rawText = match[0] ?? '';
        const target = normalizePathLinkTarget(rawText);
        if (!target) {
            continue;
        }
        const start = match.index;
        const end = start + target.length;
        matches.push({ text: target, target, start, end, type: 'path' });
    }

    UNIX_PATH_LINK_REGEX.lastIndex = 0;
    for (
        let match = UNIX_PATH_LINK_REGEX.exec(lineText);
        match;
        match = UNIX_PATH_LINK_REGEX.exec(lineText)
    ) {
        const rawText = match[1] ?? '';
        const target = normalizePathLinkTarget(rawText);
        if (!target) {
            continue;
        }

        const prefixOffset = (match[0]?.length ?? 0) - rawText.length;
        const start = match.index + Math.max(prefixOffset, 0);
        const end = start + target.length;
        matches.push({ text: target, target, start, end, type: 'path' });
    }

    if (matches.length === 0) {
        return [];
    }

    matches.sort((a, b) => {
        if (a.start !== b.start) {
            return a.start - b.start;
        }
        if (a.type !== b.type) {
            return a.type === 'url' ? -1 : 1;
        }
        return b.end - b.start - (a.end - a.start);
    });

    const deduped: DetectedTerminalLink[] = [];
    for (const candidate of matches) {
        if (candidate.end <= candidate.start) {
            continue;
        }
        const overlapsExisting = deduped.some(
            existing => candidate.start < existing.end && candidate.end > existing.start
        );
        if (overlapsExisting) {
            continue;
        }
        deduped.push(candidate);
    }

    return deduped;
}

function toSafeFileUrl(path: string): string {
    return `safe-file://${encodeURIComponent(path)}`;
}

function useTerminalSession(
    tab: TerminalTab,
    containerRef: React.RefObject<HTMLDivElement>,
    projectPath: string | undefined,
    initialTheme: ITheme
) {
    const xtermRef = useRef<XTerm | null>(null);
    const fitAddonRef = useRef<FitAddon | null>(null);
    const [isReady, setIsReady] = useState(false);
    const [hasError, setHasError] = useState(false);
    const isInitializedRef = useRef(false);
    const isMountedRef = useRef(true);
    const hasBootstrappedRef = useRef(false);

    useEffect(() => {
        isMountedRef.current = true;

        if (
            isTerminalSessionInitialized(tab.id) ||
            isTerminalSessionInitializing(tab.id) ||
            !containerRef.current ||
            isInitializedRef.current
        ) {
            return;
        }
        isInitializedRef.current = true;
        markTerminalSessionInitializing(tab.id);

        const term = new XTerm({
            cursorBlink: true,
            fontSize: 13,
            fontFamily: "'JetBrains Mono', 'Cascadia Code', Consolas, monospace",
            theme: initialTheme,
            allowProposedApi: true,
            scrollback: 10000,
            cols: 80,
            rows: 24,
        });
        const fitAddon = new FitAddon();
        term.loadAddon(fitAddon);
        term.open(containerRef.current);
        let webglAddon: { dispose: () => void } | null = null;

        const initializeGpuRenderer = async () => {
            if (
                typeof window === 'undefined' ||
                !('WebGL2RenderingContext' in window) ||
                !isMountedRef.current
            ) {
                return;
            }
            try {
                const { WebglAddon } = await import('@xterm/addon-webgl');
                if (!isMountedRef.current) {
                    return;
                }

                const addon = new WebglAddon();
                addon.onContextLoss(() => {
                    appLogger.warn(
                        'TerminalInstance',
                        'Terminal WebGL context lost, falling back to canvas renderer'
                    );
                    try {
                        addon.dispose();
                    } catch {
                        // Ignore addon disposal errors after context loss.
                    }
                    if (webglAddon === addon) {
                        webglAddon = null;
                    }
                });
                term.loadAddon(addon);
                webglAddon = addon;
            } catch (error) {
                appLogger.warn(
                    'TerminalInstance',
                    'WebGL renderer unavailable, using default terminal renderer',
                    error instanceof Error ? error : new Error(String(error))
                );
            }
        };

        void initializeGpuRenderer();
        const linkProviderDisposable = term.registerLinkProvider({
            provideLinks: (bufferLineNumber, callback) => {
                const lineText =
                    term.buffer.active.getLine(bufferLineNumber - 1)?.translateToString(true) ?? '';
                const links = resolveTerminalLineLinks(lineText);
                if (links.length === 0) {
                    callback(undefined);
                    return;
                }

                callback(
                    links.map(link => ({
                        text: link.text,
                        range: {
                            start: { x: link.start + 1, y: bufferLineNumber },
                            end: { x: link.end, y: bufferLineNumber },
                        },
                        activate: () => {
                            const target =
                                link.type === 'url' ? link.target : toSafeFileUrl(link.target);
                            try {
                                window.electron.openExternal(target);
                            } catch (error) {
                                appLogger.error(
                                    'TerminalInstance',
                                    `Failed to open terminal ${link.type} link: ${link.target}`,
                                    error instanceof Error ? error : new Error(String(error))
                                );
                            }
                        },
                    }))
                );
            },
        });
        xtermRef.current = term;
        fitAddonRef.current = fitAddon;

        let sessionCreated = false;
        const setupEvents = (id: string) => {
            term.onResize(s => {
                if (sessionCreated && isMountedRef.current) {
                    void window.electron.terminal.resize(id, s.cols, s.rows);
                }
            });
            term.onData(d => {
                if (sessionCreated && isMountedRef.current) {
                    void window.electron.terminal.write(id, d);
                }
            });
        };

        const createBackendSession = async (cols: number, rows: number) => {
            if (!isMountedRef.current) {
                return null;
            }
            if (!(await window.electron.terminal.isAvailable())) {
                if (isMountedRef.current) {
                    term.write('\r\n\x1b[31m[ERROR] Terminal service not available.\x1b[0m\r\n');
                }
                return null;
            }
            if (!isMountedRef.current) {
                return null;
            }
            const sessionId = await window.electron.terminal.create({
                id: tab.id,
                shell: tab.type,
                ...(tab.backendId ? { backendId: tab.backendId } : {}),
                ...(projectPath ? { cwd: projectPath } : {}),
                ...(tab.metadata ? { metadata: tab.metadata } : {}),
                cols,
                rows,
            });
            if (!sessionId && isMountedRef.current) {
                term.write(`\r\n\x1b[31m[ERROR] Failed to create session\x1b[0m\r\n`);
                return null;
            }
            return sessionId;
        };

        const initSession = async () => {
            if (isTerminalSessionInitialized(tab.id)) {
                return;
            }
            await new Promise(resolve => {
                setTimeout(resolve, 50);
            });
            if (!isMountedRef.current) {
                clearTerminalSessionFlags(tab.id);
                return;
            }
            try {
                if (containerRef.current?.offsetParent) {
                    fitAddon.fit();
                }
            } catch {
                // Ignore fit failure on init.
            }
            const result = await createBackendSession(term.cols || 80, term.rows || 24);
            if (!isMountedRef.current) {
                clearTerminalSessionFlags(tab.id);
                return;
            }
            if (!result) {
                setHasError(true);
                clearTerminalSessionFlags(tab.id);
                return;
            }
            sessionCreated = true;
            markTerminalSessionInitialized(tab.id);
            setupEvents(tab.id);
            try {
                const buffer = await window.electron.terminal.readBuffer(tab.id);
                if (buffer && isMountedRef.current) {
                    term.write(buffer);
                }
            } catch {
                // Ignore readBuffer failure.
            }
            if (isMountedRef.current) {
                setIsReady(true);
            }

            if (
                !hasBootstrappedRef.current &&
                typeof tab.bootstrapCommand === 'string' &&
                tab.bootstrapCommand.trim()
            ) {
                hasBootstrappedRef.current = true;
                window.setTimeout(() => {
                    if (isMountedRef.current) {
                        void window.electron.terminal.write(
                            tab.id,
                            `${tab.bootstrapCommand?.trim() ?? ''}\r`
                        );
                    }
                }, 120);
            }
        };

        void initSession();

        return () => {
            isMountedRef.current = false;
            isInitializedRef.current = false;
            xtermRef.current = null;
            fitAddonRef.current = null;

            if (sessionCreated) {
                clearTerminalSessionFlags(tab.id);
                void window.electron.terminal.kill(tab.id);
            } else {
                clearTerminalSessionFlags(tab.id);
            }
            if (webglAddon) {
                try {
                    webglAddon.dispose();
                } catch {
                    // Ignore addon disposal errors.
                }
            }
            linkProviderDisposable.dispose();
            try {
                term.dispose();
            } catch {
                // Ignore terminal disposal errors.
            }
        };
    }, [
        containerRef,
        initialTheme,
        projectPath,
        tab.backendId,
        tab.bootstrapCommand,
        tab.id,
        tab.metadata,
        tab.type,
    ]);

    return { xtermRef, fitAddonRef, isReady, hasError };
}

type TerminalInstanceProps = {
    tab: TerminalTab;
    isVisible: boolean;
    className?: string;
    onActivate?: () => void;
    onClose: () => void;
    projectPath?: string;
    onTerminalInstanceChange?: (id: string, terminal: XTerm | null) => void;
    appearance: TerminalAppearancePreferences;
    resolvedAppearance: ResolvedTerminalAppearance;
};

export const TerminalInstance = memo(({
    tab,
    isVisible,
    className,
    onActivate,
    onClose,
    projectPath,
    onTerminalInstanceChange,
    appearance,
    resolvedAppearance,
}: TerminalInstanceProps) => {
    const { t } = useTranslation();
    const containerRef = useRef<HTMLDivElement>(null);
    const { xtermRef, fitAddonRef, isReady, hasError } = useTerminalSession(
        tab,
        containerRef,
        projectPath,
        resolvedAppearance.theme
    );

    useTerminalSmartSuggestions({
        xtermRef,
        tabId: tab.id,
        shell: tab.type,
        cwd: projectPath,
        enabled: isReady && isVisible,
    });

    useEffect(() => {
        if (!xtermRef.current) {
            return;
        }
        const terminal = xtermRef.current;
        terminal.options.theme = resolvedAppearance.theme;
        terminal.options.fontFamily = resolvedAppearance.fontFamily;
        terminal.options.allowTransparency = appearance.surfaceOpacity < 1;
        terminal.options.cursorStyle = resolvedAppearance.cursorStyle;
        terminal.options.cursorBlink = resolvedAppearance.cursorBlink;
        terminal.options.fontSize = resolvedAppearance.fontSize;
        terminal.options.lineHeight = resolvedAppearance.lineHeight;

        const xtermRoot = containerRef.current?.querySelector('.xterm') as HTMLElement | null;
        if (xtermRoot) {
            xtermRoot.style.fontFeatureSettings = appearance.ligatures
                ? '"liga" 1, "calt" 1'
                : '"liga" 0, "calt" 0';
            xtermRoot.style.fontVariantLigatures = appearance.ligatures ? 'normal' : 'none';
            if (resolvedAppearance.theme.background) {
                xtermRoot.style.backgroundColor = resolvedAppearance.theme.background;
            }
        }
        const xtermViewport = containerRef.current?.querySelector('.xterm-viewport') as
            | HTMLElement
            | null;
        if (xtermViewport) {
            xtermViewport.style.backgroundColor =
                resolvedAppearance.theme.background ?? 'transparent';
        }

        if (isVisible) {
            try {
                fitAddonRef.current?.fit();
            } catch {
                // Ignore fit failures during visibility/theme transitions.
            }
        }
        if (terminal.rows > 0) {
            terminal.refresh(0, terminal.rows - 1);
        }
    }, [appearance, fitAddonRef, isVisible, resolvedAppearance, xtermRef]);

    const safeFit = useCallback(() => {
        if (!fitAddonRef.current || !containerRef.current || !isVisible) {
            return;
        }
        try {
            if (containerRef.current.offsetParent) {
                fitAddonRef.current.fit();
            }
        } catch {
            // Ignore fit failure.
        }
    }, [fitAddonRef, isVisible]);

    useEffect(() => {
        if (!isReady || !xtermRef.current) {
            return;
        }
        const handleData = (event: Event) => {
            const detail = (event as CustomEvent).detail;
            if (detail?.id === tab.id && xtermRef.current) {
                xtermRef.current.write(detail.data);
            }
        };
        const handleExit = (event: Event) => {
            const detail = (event as CustomEvent).detail;
            if (detail?.id === tab.id) {
                if (xtermRef.current) {
                    xtermRef.current.write(
                        `\r\n\x1b[33m[Terminal exited with code ${detail.code ?? 0}]\x1b[0m\r\n`
                    );
                }
                onClose();
            }
        };
        window.addEventListener('terminal-data-multiplex', handleData);
        window.addEventListener('terminal-exit-multiplex', handleExit);
        return () => {
            window.removeEventListener('terminal-data-multiplex', handleData);
            window.removeEventListener('terminal-exit-multiplex', handleExit);
        };
    }, [isReady, onClose, tab.id, xtermRef]);

    useEffect(() => {
        if (!isVisible) {
            return;
        }
        const timer = setTimeout(safeFit, 100);
        return () => {
            clearTimeout(timer);
        };
    }, [isVisible, safeFit]);

    useEffect(() => {
        if (!containerRef.current) {
            return;
        }
        const observer = new ResizeObserver(() => {
            if (isVisible) {
                safeFit();
            }
        });
        observer.observe(containerRef.current);
        return () => {
            observer.disconnect();
        };
    }, [isVisible, safeFit]);

    useEffect(() => {
        onTerminalInstanceChange?.(tab.id, isReady ? xtermRef.current : null);
        return () => {
            onTerminalInstanceChange?.(tab.id, null);
        };
    }, [isReady, onTerminalInstanceChange, tab.id, xtermRef]);

    return (
        <div
            className={cn('h-full w-full bg-background relative', isVisible ? 'block' : 'hidden', className)}
            style={{ backgroundColor: resolvedAppearance.theme.background ?? undefined }}
            onMouseDown={() => {
                onActivate?.();
            }}
        >
            {hasError && (
                <div className="absolute inset-0 flex items-center justify-center bg-background/80 z-10">
                    <div className="text-center px-4">
                        <p className="text-destructive text-sm mb-1">{t('terminal.sessionFailed')}</p>
                        <p className="text-muted-foreground text-xs">{t('terminal.closeAndCreate')}</p>
                    </div>
                </div>
            )}
            <div
                ref={containerRef}
                className="h-full w-full"
                style={{ backgroundColor: resolvedAppearance.theme.background ?? undefined }}
            />
        </div>
    );
});

/**
 * Terminal Panel Component
 * VSCode-style terminal panel with bottom slide-up behavior
 */

import { TerminalPanelState, TerminalSession } from '@shared/types/terminal-v2';
import { FitAddon } from '@xterm/addon-fit';
import { Terminal } from '@xterm/xterm';
import { Plus, X } from 'lucide-react';
import React, { useCallback, useEffect, useRef, useState } from 'react';

import { useTranslation } from '@/i18n';
import { appLogger } from '@/utils/renderer-logger';

import { TerminalConnectionSelector } from './TerminalConnectionSelector';

import './TerminalPanel.css';
import './TerminalConnectionSelector.css';

const TERMINAL_MIN_HEIGHT = 100;
const TERMINAL_DEFAULT_HEIGHT = 300;
const TERMINAL_MAX_HEIGHT = 800;

export const TerminalPanel: React.FC = () => {
    const { t } = useTranslation();
    const [panelState, setPanelState] = useState<TerminalPanelState>({
        isOpen: false,
        height: TERMINAL_DEFAULT_HEIGHT,
        activeSessionId: null,
        sessions: [],
        splitMode: 'single',
    });

    const [isResizing, setIsResizing] = useState(false);
    const [showSelector, setShowSelector] = useState(false);
    const panelRef = useRef<HTMLDivElement>(null);
    const terminalRefs = useRef<Map<string, { terminal: Terminal; fitAddon: FitAddon }>>(new Map());
    const restoreAttemptedRef = useRef(false);

    const toggleTerminal = useCallback(() => {
        setPanelState(prev => ({
            ...prev,
            isOpen: !prev.isOpen,
        }));
    }, []);

    const createTerminalSession = useCallback(
        async (
            type: 'local' | 'ssh' | 'docker',
            name: string,
            metadata?: Record<string, unknown>
        ) => {
            try {
                const backendId = type === 'local' ? 'node-pty' : type;
                const sessionId = (await window.electron.invoke('terminal:create', {
                    cols: 80,
                    rows: 24,
                    backendId,
                    metadata,
                })) as string;

                const newSession: TerminalSession = {
                    id: sessionId,
                    title: name || `${t('terminal.title')} ${panelState.sessions.length + 1}`,
                    cwd: '',
                    shell:
                        type === 'local'
                            ? process.platform === 'win32'
                                ? 'powershell.exe'
                                : '/bin/bash'
                            : (metadata?.shell as string) || '',
                    backendType: 'xterm',
                    status: 'running',
                    createdAt: Date.now(),
                    lastActive: Date.now(),
                };

                setPanelState(prev => ({
                    ...prev,
                    isOpen: true,
                    activeSessionId: sessionId,
                    sessions: [...prev.sessions, newSession],
                }));
            } catch (error) {
                appLogger.error('TerminalPanel', 'Failed to create terminal', error as Error);
            }
        },
        [t, panelState.sessions.length]
    );

    const createNewTerminal = useCallback(async () => {
        await createTerminalSession(
            'local',
            `${t('terminal.title')} ${panelState.sessions.length + 1}`
        );
    }, [createTerminalSession, t, panelState.sessions.length]);

    // Keyboard shortcuts
    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if (e.ctrlKey && e.key === '`') {
                e.preventDefault();
                toggleTerminal();
            } else if (e.ctrlKey && e.shiftKey && e.key === '~') {
                e.preventDefault();
                void createNewTerminal();
            }
        };

        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [toggleTerminal, createNewTerminal]);

    const closeTerminal = async (sessionId: string) => {
        try {
            await window.electron.invoke('terminal:close', sessionId);

            setPanelState(prev => {
                const newSessions = prev.sessions.filter(s => s.id !== sessionId);
                const newActiveId =
                    prev.activeSessionId === sessionId
                        ? newSessions.length > 0
                            ? newSessions[0].id
                            : null
                        : prev.activeSessionId;

                return {
                    ...prev,
                    sessions: newSessions,
                    activeSessionId: newActiveId,
                    isOpen: newSessions.length > 0 ? prev.isOpen : false,
                };
            });

            const terminalInstance = terminalRefs.current.get(sessionId);
            if (terminalInstance) {
                terminalInstance.terminal.dispose();
                terminalRefs.current.delete(sessionId);
            }
        } catch (error) {
            appLogger.error('TerminalPanel', 'Failed to close terminal', error as Error);
        }
    };

    const switchTerminal = (sessionId: string) => {
        setPanelState(prev => ({
            ...prev,
            activeSessionId: sessionId,
        }));
    };

    const renameTerminal = useCallback(async (sessionId: string) => {
        const current = panelState.sessions.find(s => s.id === sessionId);
        if (!current) {
            return;
        }
        const next = window.prompt(t('terminal.renamePrompt') || 'New terminal name', current.title);
        if (!next?.trim() || next.trim() === current.title) {
            return;
        }
        const title = next.trim();
        await window.electron.invoke('terminal:setSessionTitle', sessionId, title);
        setPanelState(prev => ({
            ...prev,
            sessions: prev.sessions.map(s => (s.id === sessionId ? { ...s, title } : s)),
        }));
    }, [panelState.sessions, t]);

    const initializeTerminal = (sessionId: string, container: HTMLDivElement) => {
        if (terminalRefs.current.has(sessionId)) {
            return;
        }

        const terminal = new Terminal({
            cursorBlink: true,
            fontSize: 14,
            fontFamily: 'Consolas, "Courier New", monospace',
            theme: {
                background: '#1e1e1e',
                foreground: '#cccccc',
            },
        });

        const fitAddon = new FitAddon();
        terminal.loadAddon(fitAddon);
        terminal.open(container);
        fitAddon.fit();

        terminalRefs.current.set(sessionId, { terminal, fitAddon });

        terminal.onData((data: string) => {
            void window.electron.invoke('terminal:write', sessionId, data);
        });
    };

    const handleResizeStart = (e: React.MouseEvent) => {
        e.preventDefault();
        setIsResizing(true);
    };

    useEffect(() => {
        if (!isResizing) {
            return;
        }

        const handleMouseMove = (e: MouseEvent) => {
            const newHeight = window.innerHeight - e.clientY;
            const clampedHeight = Math.max(
                TERMINAL_MIN_HEIGHT,
                Math.min(TERMINAL_MAX_HEIGHT, newHeight)
            );
            setPanelState(prev => ({ ...prev, height: clampedHeight }));
        };

        const handleMouseUp = () => setIsResizing(false);

        document.addEventListener('mousemove', handleMouseMove);
        document.addEventListener('mouseup', handleMouseUp);

        return () => {
            document.removeEventListener('mousemove', handleMouseMove);
            document.removeEventListener('mouseup', handleMouseUp);
        };
    }, [isResizing]);

    useEffect(() => {
        if (restoreAttemptedRef.current) {
            return;
        }
        restoreAttemptedRef.current = true;

        const restoreSnapshots = async () => {
            try {
                const snapshots = (await window.electron.invoke('terminal:getSnapshotSessions')) as Array<{
                    id: string;
                    shell: string;
                    cwd: string;
                    title?: string;
                    timestamp: number;
                }>;
                if (!Array.isArray(snapshots) || snapshots.length === 0) {
                    return;
                }

                const result = (await window.electron.invoke('terminal:restoreAllSnapshots')) as {
                    restored: number;
                    failed: number;
                    sessionIds: string[];
                };
                if (!result || result.restored <= 0 || !Array.isArray(result.sessionIds)) {
                    return;
                }

                const restored = snapshots
                    .filter(s => result.sessionIds.includes(s.id))
                    .map(s => ({
                        id: s.id,
                        title: s.title?.trim() || `${t('terminal.title')} (restored)`,
                        cwd: s.cwd,
                        shell: s.shell,
                        backendType: 'xterm' as const,
                        status: 'running' as const,
                        createdAt: s.timestamp,
                        lastActive: Date.now(),
                    }));

                if (restored.length === 0) {
                    return;
                }

                setPanelState(prev => {
                    if (prev.sessions.length > 0) {
                        return prev;
                    }
                    return {
                        ...prev,
                        isOpen: true,
                        sessions: restored,
                        activeSessionId: restored[0]?.id ?? null,
                    };
                });
            } catch (error) {
                appLogger.error('TerminalPanel', 'Failed to restore snapshot sessions', error as Error);
            }
        };

        void restoreSnapshots();
    }, [t]);

    if (!panelState.isOpen) {
        return null;
    }

    return (
        <div ref={panelRef} className="terminal-panel" style={{ height: `${panelState.height}px` }}>
            <div className="terminal-resize-handle" onMouseDown={handleResizeStart} />

            <div className="terminal-header">
                <div className="terminal-tabs">
                    {panelState.sessions.map(session => (
                        <div
                            key={session.id}
                            className={`terminal-tab ${session.id === panelState.activeSessionId ? 'active' : ''}`}
                            onClick={() => switchTerminal(session.id)}
                            onDoubleClick={() => void renameTerminal(session.id)}
                        >
                            <span>{session.title}</span>
                            <button
                                onClick={e => {
                                    e.stopPropagation();
                                    void closeTerminal(session.id);
                                }}
                            >
                                <X size={14} />
                            </button>
                        </div>
                    ))}
                </div>

                <div className="terminal-actions">
                    <button onClick={() => setShowSelector(true)} title={t('terminal.new')}>
                        <Plus size={18} />
                    </button>
                    <button onClick={toggleTerminal} title={t('terminal.hide')}>
                        <X size={18} />
                    </button>
                </div>
            </div>

            {showSelector && (
                <TerminalConnectionSelector
                    onSelect={option =>
                        void createTerminalSession(option.type, option.name, option.metadata)
                    }
                    onClose={() => setShowSelector(false)}
                />
            )}

            <div className="terminal-container">
                {panelState.sessions.map(session => (
                    <div
                        key={session.id}
                        className={
                            session.id === panelState.activeSessionId
                                ? 'terminal-view active'
                                : 'terminal-view'
                        }
                        ref={el =>
                            el &&
                            session.id === panelState.activeSessionId &&
                            initializeTerminal(session.id, el)
                        }
                    />
                ))}
            </div>
        </div>
    );
};

/**
 * App State Management Hook
 * Centralizes UI state management for the App component
 */

import { useCallback, useEffect, useMemo, useRef, useState } from 'react';

import {
    dismissNotification,
    pushNotification,
    toActiveToasts,
    useNotificationCenterStore,
} from '@/store/notification-center.store';
import { setAppShellState, useUiLayoutStore } from '@/store/ui-layout.store';
import { Toast } from '@/types';
// SettingsCategory type is used by dependent modules via AppState interface

export type AppView = 'chat' | 'projects' | 'settings' | 'mcp' | 'memory' | 'ideas' | 'project-agent' | 'docker' | 'terminal' | 'models'

export interface AppState {
    // View state
    currentView: AppView
    setCurrentView: (view: AppView) => void

    // UI state
    isSidebarCollapsed: boolean
    setIsSidebarCollapsed: (collapsed: boolean) => void
    isDragging: boolean
    setIsDragging: (dragging: boolean) => void

    // Modal state
    showCommandPalette: boolean
    setShowCommandPalette: (show: boolean) => void
    showSSHManager: boolean
    setShowSSHManager: (show: boolean) => void
    showShortcuts: boolean
    setShowShortcuts: (show: boolean) => void
    showFileMenu: boolean
    setShowFileMenu: (show: boolean) => void
    showScrollButton: boolean
    setShowScrollButton: (show: boolean) => void
    isAudioOverlayOpen: boolean
    setIsAudioOverlayOpen: (open: boolean) => void

    // Toast notifications
    toasts: Toast[]
    addToast: (toast: Omit<Toast, 'id'>) => void
    removeToast: (id: string) => void

    // Refs
    fileInputRef: React.RefObject<HTMLInputElement>
    textareaRef: React.RefObject<HTMLTextAreaElement>
    messagesEndRef: React.RefObject<HTMLDivElement>
}

/**
 * Centralized app state management hook
 */
export function useAppState(): AppState {
    // View state
    const [currentView, setCurrentView] = useState<AppView>('chat');

    // UI state
    const persistedSidebarCollapsed = useUiLayoutStore(snapshot => snapshot.appShell.sidebarCollapsed);
    const [isSidebarCollapsed, setIsSidebarCollapsedState] = useState(persistedSidebarCollapsed);
    const [isDragging, setIsDragging] = useState(false);

    // Modal state
    const [showCommandPalette, setShowCommandPalette] = useState(false);
    const [showSSHManager, setShowSSHManager] = useState(false);
    const [showShortcuts, setShowShortcuts] = useState(false);
    const [showFileMenu, setShowFileMenu] = useState(false);
    const [showScrollButton, setShowScrollButton] = useState(false);
    const [isAudioOverlayOpen, setIsAudioOverlayOpen] = useState(false);

    useEffect(() => {
        setIsSidebarCollapsedState(persistedSidebarCollapsed);
    }, [persistedSidebarCollapsed]);

    const setIsSidebarCollapsed = useCallback((collapsed: boolean) => {
        setIsSidebarCollapsedState(collapsed);
        setAppShellState({ sidebarCollapsed: collapsed });
    }, []);

    // Toast notifications (shared notification center)
    const activeNotifications = useNotificationCenterStore(snapshot => snapshot.active);
    const toasts = useMemo(() => toActiveToasts(activeNotifications), [activeNotifications]);

    const addToast = useCallback((toast: Omit<Toast, 'id'>) => {
        pushNotification({
            type: toast.type,
            message: toast.message,
            source: 'app',
        });
    }, []);

    const removeToast = useCallback((id: string) => {
        dismissNotification(id);
    }, []);

    // Refs
    const fileInputRef = useRef<HTMLInputElement>(null);
    const textareaRef = useRef<HTMLTextAreaElement>(null);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    return useMemo(() => ({
        currentView,
        setCurrentView,
        isSidebarCollapsed,
        setIsSidebarCollapsed,
        isDragging,
        setIsDragging,
        showCommandPalette,
        setShowCommandPalette,
        showSSHManager,
        setShowSSHManager,
        showShortcuts,
        setShowShortcuts,
        showFileMenu,
        setShowFileMenu,
        showScrollButton,
        setShowScrollButton,
        isAudioOverlayOpen,
        setIsAudioOverlayOpen,
        toasts,
        addToast,
        removeToast,
        fileInputRef,
        textareaRef,
        messagesEndRef
    }), [
        currentView,
        isSidebarCollapsed,
        isDragging,
        showCommandPalette,
        showSSHManager,
        showShortcuts,
        showFileMenu,
        showScrollButton,
        isAudioOverlayOpen,
        toasts,
        addToast,
        removeToast
    ]);
}

